public class ShaderExample {
    public static void main(String[] args) {
        int program = GL20.glCreateProgram();
        loadShader(GL20.GL_VERTEX_SHADER, getText("shader"), program);
        loadShader(GL20.GL_FRAGMENT_SHADER, getText("fragmentShader"), program);
        validateProgram(program);

        Shader shader = new Shader(program);
        shader.bind();
    }
}

